#include<bits/stdc++.h>
using namespace std;
long long n,a[1000010],b[1000010],nxt[1000010];
bool check(long long x)
{
    long long coin=0,s=0;
    for(long long i=1;i<=n;i++)
    {
        s+=b[i];
        if(s*a[i]+coin<(nxt[i]-1)*x)
        {
            coin+=s*a[i];
            s=0;
        }
        else if((nxt[i]-1)*x>coin)
        {
            long long tmp=((nxt[i]-1)*x-coin+a[i]-1)/a[i];
            tmp=min(tmp,s);
            coin+=tmp*a[i];
            s-=tmp;
        }
        if(coin<i*x)
        {
            return false;
        }
    }
    return true;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        scanf("%lld",&n);
        for(long long i=1;i<=n;i++)
        {
            nxt[i]=n+1;
            scanf("%lld",&a[i]);
        }
        nxt[0]=nxt[n+1]=0;
        a[n+1]=b[n+1]=0;
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&b[i]);
        }
        stack<long long> s;
        for(long long i=1;i<=n;i++)
        {
            while(!s.empty()&&a[s.top()]<a[i])
            {
                nxt[s.top()]=i;
                s.pop();
            }
            s.push(i);
        }
        long long l=0,r=1e15,best=0;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            if(check(mid))
            {
                l=mid+1;
                best=mid;
            }
            else
            {
                r=mid-1;
            }
        }
        printf("%lld\n",best);
    }
    return 0;
}
